import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Check, ChevronRight, FlaskConical, Users, Eye } from 'lucide-react';
import PlatformLayout from '../components/platform/PlatformLayout';
import Button from '../components/ui/Button';
import { useAppData } from '../context/DataContext';

const testTypeOptions = [
  { id: 'bug-hunt', label: 'Bug Hunt', icon: '🐛', desc: 'Find defects & crashes', canonical: 'Bug Hunt' },
  { id: 'usability', label: 'Usability Study', icon: '🎯', desc: 'UX feedback & recordings', canonical: 'Usability' },
  { id: 'load-test', label: 'Load Test', icon: '⚡', desc: 'Performance under load', canonical: 'Load Test' },
  { id: 'multi-day', label: 'Multi-Day Study', icon: '📅', desc: 'Longitudinal feedback', canonical: 'Multi-Day' },
  { id: 'fintech', label: 'Fintech & Payments', icon: '💳', desc: 'Real transaction testing', canonical: 'Fintech' },
  { id: 'game', label: 'Game Playtesting', icon: '🎮', desc: 'Multiplayer & performance', canonical: 'Game' },
];

const platforms = ['iOS', 'Android', 'Web', 'macOS', 'Windows', 'API'];
const expertiseOptions = ['General Consumer', 'Developer', 'QA Professional', 'Domain Expert', 'Power User'];

const steps = [
  { id: 1, label: 'Test Details', icon: FlaskConical },
  { id: 2, label: 'Tester Criteria', icon: Users },
  { id: 3, label: 'Review & Launch', icon: Eye },
];

export default function CreateTest() {
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [launching, setLaunching] = useState(false);
  const [form, setForm] = useState({
    name: '',
    type: '',
    description: '',
    startDate: '',
    endDate: '',
    testerCount: 20,
    platforms: [],
    expertise: [],
    ageRange: '18-65',
    countries: 'United States',
    compensation: 35,
    nda: true,
    briefing: '',
  });

  const set = (key, val) => setForm((f) => ({ ...f, [key]: val }));

  const toggleArray = (key, val) =>
    setForm((f) => ({
      ...f,
      [key]: f[key].includes(val) ? f[key].filter((v) => v !== val) : [...f[key], val],
    }));

  const handleLaunch = async () => {
    setLaunching(true);
    await new Promise((res) => setTimeout(res, 1200));
    navigate('/company/dashboard');
  };

  return (
    <PlatformLayout title="Create New Test">
      <div className="p-6 max-w-3xl mx-auto">
        {/* Stepper */}
        <div className="flex items-center mb-10">
          {steps.map((s, idx) => {
            const done = step > s.id;
            const active = step === s.id;
            const Icon = s.icon;
            return (
              <React.Fragment key={s.id}>
                <div className="flex items-center gap-3">
                  <div
                    className={`w-9 h-9 rounded-full flex items-center justify-center flex-shrink-0 transition-all
                      ${done ? 'bg-brand-600 text-white' : active ? 'bg-brand-600 text-white shadow-glow' : 'bg-slate-100 text-slate-400'}`}
                  >
                    {done ? <Check size={16} /> : <Icon size={16} />}
                  </div>
                  <div>
                    <p className={`text-xs font-semibold ${active ? 'text-brand-600' : done ? 'text-slate-700' : 'text-slate-400'}`}>
                      Step {s.id}
                    </p>
                    <p className={`text-sm font-medium hidden sm:block ${active ? 'text-slate-900' : 'text-slate-500'}`}>
                      {s.label}
                    </p>
                  </div>
                </div>
                {idx < steps.length - 1 && (
                  <div className={`flex-1 h-0.5 mx-4 transition-colors ${done ? 'bg-brand-500' : 'bg-slate-200'}`} />
                )}
              </React.Fragment>
            );
          })}
        </div>

        {/* Step 1: Test Details */}
        {step === 1 && (
          <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-6 space-y-5">
            <h2 className="font-display font-bold text-xl text-slate-900">Test Details</h2>

            <div>
              <label className="form-label">Test Name *</label>
              <input
                type="text"
                className="form-input"
                placeholder="e.g., Mobile App v3.1 — Bug Hunt"
                value={form.name}
                onChange={(e) => set('name', e.target.value)}
              />
            </div>

            <div>
              <label className="form-label">Test Type *</label>
              <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                {testTypeOptions.map((t) => (
                  <button
                    key={t.id}
                    type="button"
                    onClick={() => set('type', t.id)}
                    className={`flex items-start gap-3 p-3 rounded-xl border-2 text-left transition-all
                      ${form.type === t.id
                        ? 'border-brand-500 bg-brand-50'
                        : 'border-slate-200 hover:border-slate-300'}`}
                  >
                    <span className="text-2xl leading-none">{t.icon}</span>
                    <div>
                      <p className={`text-xs font-semibold ${form.type === t.id ? 'text-brand-700' : 'text-slate-700'}`}>
                        {t.label}
                      </p>
                      <p className="text-[11px] text-slate-400 mt-0.5">{t.desc}</p>
                    </div>
                  </button>
                ))}
              </div>
            </div>

            <div>
              <label className="form-label">Description</label>
              <textarea
                className="form-input min-h-[100px] resize-none"
                placeholder="Describe what testers should focus on, known issues to investigate, or key user flows to test..."
                value={form.description}
                onChange={(e) => set('description', e.target.value)}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="form-label">Start Date</label>
                <input type="date" className="form-input" value={form.startDate} onChange={(e) => set('startDate', e.target.value)} />
              </div>
              <div>
                <label className="form-label">End Date</label>
                <input type="date" className="form-input" value={form.endDate} onChange={(e) => set('endDate', e.target.value)} />
              </div>
            </div>

            <div className="flex justify-end pt-2">
              <Button
                onClick={() => setStep(2)}
                disabled={!form.name || !form.type}
                iconRight={<ChevronRight size={16} />}
              >
                Continue
              </Button>
            </div>
          </div>
        )}

        {/* Step 2: Tester Criteria */}
        {step === 2 && (
          <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-6 space-y-5">
            <h2 className="font-display font-bold text-xl text-slate-900">Tester Criteria</h2>

            <div>
              <label className="form-label">Number of Testers: <span className="text-brand-600 font-bold">{form.testerCount}</span></label>
              <input
                type="range"
                min="5"
                max="200"
                step="5"
                value={form.testerCount}
                onChange={(e) => set('testerCount', Number(e.target.value))}
                className="w-full accent-brand-600 mt-1"
              />
              <div className="flex justify-between text-xs text-slate-400 mt-1">
                <span>5</span><span>200</span>
              </div>
            </div>

            <div>
              <label className="form-label">Target Platforms *</label>
              <div className="flex flex-wrap gap-2">
                {platforms.map((p) => (
                  <button
                    key={p}
                    type="button"
                    onClick={() => toggleArray('platforms', p)}
                    className={`px-3.5 py-1.5 rounded-lg text-sm font-medium border transition-all
                      ${form.platforms.includes(p)
                        ? 'bg-brand-600 border-brand-600 text-white'
                        : 'bg-white border-slate-200 text-slate-600 hover:border-brand-300'}`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            </div>

            <div>
              <label className="form-label">Tester Expertise</label>
              <div className="flex flex-wrap gap-2">
                {expertiseOptions.map((e) => (
                  <button
                    key={e}
                    type="button"
                    onClick={() => toggleArray('expertise', e)}
                    className={`px-3.5 py-1.5 rounded-lg text-sm font-medium border transition-all
                      ${form.expertise.includes(e)
                        ? 'bg-accent-500 border-accent-500 text-white'
                        : 'bg-white border-slate-200 text-slate-600 hover:border-accent-300'}`}
                  >
                    {e}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="form-label">Country / Region</label>
                <input
                  type="text"
                  className="form-input"
                  value={form.countries}
                  onChange={(e) => set('countries', e.target.value)}
                  placeholder="United States, UK, Global..."
                />
              </div>
              <div>
                <label className="form-label">Tester Compensation ($)</label>
                <input
                  type="number"
                  className="form-input"
                  value={form.compensation}
                  onChange={(e) => set('compensation', Number(e.target.value))}
                  min="10"
                  step="5"
                />
              </div>
            </div>

            <div className="flex items-center gap-3 p-3 bg-slate-50 rounded-lg">
              <input
                type="checkbox"
                id="nda"
                checked={form.nda}
                onChange={(e) => set('nda', e.target.checked)}
                className="w-4 h-4 accent-brand-600"
              />
              <label htmlFor="nda" className="text-sm text-slate-700 cursor-pointer">
                Require NDA agreement from testers (recommended for unreleased products)
              </label>
            </div>

            <div className="flex justify-between pt-2">
              <Button variant="secondary" onClick={() => setStep(1)}>Back</Button>
              <Button
                onClick={() => setStep(3)}
                disabled={form.platforms.length === 0}
                iconRight={<ChevronRight size={16} />}
              >
                Review Test
              </Button>
            </div>
          </div>
        )}

        {/* Step 3: Review */}
        {step === 3 && (
          <div className="space-y-5">
            <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-6">
              <h2 className="font-display font-bold text-xl text-slate-900 mb-5">Review Your Test</h2>

              <div className="space-y-3">
                {[
                  { label: 'Test Name', value: form.name },
                  { label: 'Type', value: testTypeOptions.find((t) => t.id === form.type)?.label },
                  { label: 'Duration', value: `${form.startDate} → ${form.endDate}` },
                  { label: 'Testers Needed', value: `${form.testerCount} testers` },
                  { label: 'Platforms', value: form.platforms.join(', ') || 'Not specified' },
                  { label: 'Expertise', value: form.expertise.join(', ') || 'General' },
                  { label: 'Countries', value: form.countries },
                  { label: 'Compensation per Tester', value: `$${form.compensation}` },
                  { label: 'Estimated Total Cost', value: `$${(form.testerCount * form.compensation).toLocaleString()}` },
                  { label: 'NDA Required', value: form.nda ? 'Yes' : 'No' },
                ].map(({ label, value }) => (
                  <div key={label} className="flex items-center justify-between py-2 border-b border-slate-50 last:border-0">
                    <span className="text-sm text-slate-500">{label}</span>
                    <span className="text-sm font-semibold text-slate-900">{value || '—'}</span>
                  </div>
                ))}
              </div>
            </div>

            <div className="bg-brand-50 border border-brand-100 rounded-xl p-4 text-sm text-brand-800">
              <p className="font-semibold mb-1">Ready to launch?</p>
              <p className="text-brand-700">Your test will go live immediately and testers will be notified within minutes. You can pause or modify the test at any time from your dashboard.</p>
            </div>

            <div className="flex justify-between">
              <Button variant="secondary" onClick={() => setStep(2)}>Back</Button>
              <Button onClick={handleLaunch} loading={launching} size="lg">
                {launching ? 'Launching...' : '🚀 Launch Test'}
              </Button>
            </div>
          </div>
        )}
      </div>
    </PlatformLayout>
  );
}
